/**
 * Geo interface representing geolocation data extracted from CDN headers.
 */
export interface Geo {
  city?: string
  country?: string
  countryCode?: string
  region?: string
  latitude?: string
  longitude?: string
  timezone?: string
}

/**
 * Mapping from ISO 3166-1 alpha-2 country codes to country names.
 */
export const COUNTRY_NAMES: ReadonlyMap<string, string> = new Map([
  ['US', 'United States'],
  ['GB', 'United Kingdom'],
  ['DE', 'Germany'],
  ['FR', 'France'],
  ['JP', 'Japan'],
  ['CN', 'China'],
  ['IN', 'India'],
  ['BR', 'Brazil'],
  ['AU', 'Australia'],
  ['CA', 'Canada'],
])

/**
 * Extract geolocation data from a Headers object.
 *
 * Reads Vercel CDN headers (x-vercel-ip-*) with a Cloudflare fallback
 * (cf-ipcountry) for the country code.
 */
export function geoFromHeaders(headers: Headers): Geo {
  const city = headers.get('x-vercel-ip-city') || undefined
  const countryCode =
    headers.get('x-vercel-ip-country') ||
    headers.get('cf-ipcountry') ||
    undefined
  const region = headers.get('x-vercel-ip-country-region') || undefined
  const latitude = headers.get('x-vercel-ip-latitude') || undefined
  const longitude = headers.get('x-vercel-ip-longitude') || undefined
  const timezone = headers.get('x-vercel-ip-timezone') || undefined

  const country = countryCode
    ? COUNTRY_NAMES.get(countryCode.toUpperCase()) || undefined
    : undefined

  return { city, country, countryCode, region, latitude, longitude, timezone }
}

/**
 * Extract geolocation data from a request-like object with headers.
 * Follows the same pattern as userAgent({ headers }) from next/server.
 */
export function geo({ headers }: { headers: Headers }): Geo {
  return geoFromHeaders(headers)
}

/**
 * Check whether a Geo object's countryCode matches any of the given region codes.
 * Comparison is case-insensitive.
 */
export function isInRegion(geoData: Geo, regions: string[]): boolean {
  const code = geoData.countryCode
  if (!code) {
    return false
  }
  const upperCode = code.toUpperCase()
  return regions.some((r) => r.toUpperCase() === upperCode)
}

/**
 * Calculate the great-circle distance between two points on Earth
 * using the Haversine formula.
 *
 * @param lat1 - Latitude of point 1 in degrees (as string from header)
 * @param lon1 - Longitude of point 1 in degrees (as string from header)
 * @param lat2 - Latitude of point 2 in degrees (as string from header)
 * @param lon2 - Longitude of point 2 in degrees (as string from header)
 * @returns Distance in kilometers
 */
export function geoDistance(
  lat1: string,
  lon1: string,
  lat2: string,
  lon2: string
): number {
  const R = 6371 // Earth's radius in kilometers
  const toRad = (deg: number): number => (deg * Math.PI) / 180

  const lat1Num = parseFloat(lat1)
  const lon1Num = parseFloat(lon1)
  const lat2Num = parseFloat(lat2)
  const lon2Num = parseFloat(lon2)

  const dLat = toRad(lat2Num - lat1Num)
  const dLon = toRad(lon2Num - lon1Num)
  const a =
    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(toRad(lat1Num)) *
      Math.cos(toRad(lat2Num)) *
      Math.sin(dLon / 2) *
      Math.sin(dLon / 2)
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a))

  return R * c
}
